(function(w){class P{constructor(){this.worker=null;this.c=new Map();this.init()}async init(){console.log('PYTML: Init...');this.s('Loading Python...');try{const r=await fetch('https://cdn.jsdelivr.net/gh/NodeX-AR/Pytml@latest/worker.js');const c=await r.text();const b=new Blob([c],{type:'application/javascript'});const u=URL.createObjectURL(b);this.worker=new Worker(u);this.worker.onmessage=(e)=>{const{id,success,output,error}=e.data;if(this.c.has(id)){const cb=this.c.get(id);if(success){cb.resolve(output)}else{cb.reject(new Error(error))}this.c.delete(id)}};this.worker.onerror=(e)=>{this.s('Worker error: '+e.message,true)};await this.wait();this.h();this.p()}catch(e){this.s('Error: '+e.message,true)}}clean(c){let r=c.replace(/<!--[\s\S]*?-->/g,'');r=r.replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/&quot;/g,'"');return r.replace(/\r\n/g,'\n')}wait(){return new Promise((r,j)=>{const id='ready_'+Date.now();this.c.set(id,{resolve:r,reject:j});this.worker.postMessage({type:'ready',id:id});setTimeout(()=>{if(this.c.has(id)){this.c.delete(id);j(new Error('Timeout'))}},3e4)})}async run(c,i={}){const clean=this.clean(c);return new Promise((r,j)=>{const id=Date.now()+'-'+Math.random();this.c.set(id,{resolve:r,reject:j});this.worker.postMessage({type:'run',id:id,code:clean,inputs:i});setTimeout(()=>{if(this.c.has(id)){this.c.delete(id);j(new Error('Timeout'))}},1e4)})}collect(b){const i={};const f=b.closest('[data-python-form]');if(f){f.querySelectorAll('input,select,textarea').forEach(el=>{if(el.name){let v=el.value;if(el.type==='number'){v=parseFloat(v)}else if(el.type==='checkbox'){v=el.checked}i[el.name]=v}})}return i}async p(){const t=document.querySelectorAll('[data-python-text]');for(let e of t){const c=e.getAttribute('data-python-text');try{const r=await this.run(`print(${c})`);e.textContent=r.trim()}catch(e){e.textContent='Error: '+e.message}}const b=document.querySelectorAll('[data-python]');for(let btn of b){const c=btn.getAttribute('data-python');const t=btn.getAttribute('data-target');const orig=btn.textContent;btn.addEventListener('click',async()=>{const i=this.collect(btn);btn.disabled=true;btn.textContent='Processing...';try{const r=await this.run(c,i);if(t){const o=document.querySelector(t);if(o)o.textContent=r}}catch(e){if(t){const o=document.querySelector(t);if(o)o.textContent='Error: '+e.message}}finally{btn.disabled=false;btn.textContent=orig}})}}s(m,e=false){let d=document.getElementById('pytml-status');if(!d){d=document.createElement('div');d.id='pytml-status';d.style.cssText='position:fixed;bottom:20px;right:20px;background:#007acc;color:#fff;padding:10px 15px;border-radius:5px;font-family:monospace;font-size:12px;z-index:10000;box-shadow:0 2px 5px rgba(0,0,0,0.2)';document.body.appendChild(d)}d.textContent=m;if(e){d.style.background='#dc3545'}else{d.style.background='#007acc'}}h(){const d=document.getElementById('pytml-status');if(d)d.remove()}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{w.pytml=new P})}else{w.pytml=new P}})(window);
